!! 2007 Macbook Emacs

clear Lock
clear Control
clear Mod1
clear Mod4

!! Left Hand
! Escape
keycode   9 = Caps_Lock

! Tab
keycode  23 = Alt_L

! Caps Lock
keycode  66 = Control_L

! Left Control
keycode  37 = Tab

! Left Alt
keycode  64 = Escape

! Left Win
keycode 133 = Super_L

!! Right Hand
! BackSpace
keycode  22 = bar

! Backslash
keycode  51 = Alt_R

! Return
keycode  36 = Control_R

! Right Win
keycode 134 = Super_R

! Right Alt
keycode 108 = Return

! Right Menu
keycode 135 = backslash

! Right Control
keycode 105 = BackSpace

add Lock    = Caps_Lock
add Control = Control_L
add Control = Control_R
add Mod1    = Alt_L
add Mod1    = Alt_R
add Mod4    = Super_L
add Mod4    = Super_R
